INSERT INTO "email_logs" ("id","to_email","to_name","subject","html_body","text_body","source","status","error_message","created_at") VALUES('1qkp6AbMYVHZR2Irx7QEX','mraumkub@gmail.com','Watcharapon Charoenwongjongdee','มีข้อความใหม่ใน Ticket: ทดสอบ',replace('<!doctype html><html><body style="font-family:system-ui,sans-serif;color:#0f172a;">\n    <p style="margin:0 0 14px;">\n    <img src="https://portal.doaction.co.th/logo-dark.svg" alt="DoAction" width="140" style="display:block;height:auto;border:0;outline:none;text-decoration:none;" />\n  </p>\n    <p>สวัสดีคุณ Watcharapon Charoenwongjongdee</p>\n    <p>มีข้อความใหม่ใน Ticket: ทดสอบ</p>\n    <blockquote style="margin:12px 0;padding:12px;border-left:3px solid #cbd5e1;background:#f8fafc;">มาแล้วครับ</blockquote>\n    <p><a href="https://portal.doaction.co.th/tickets/AQf4RKH6TyrEktiVlBMQG">เปิด Ticket ในระบบ</a></p>\n    <p style="color:#64748b;">— DoAction</p>\n  </body></html>','\n',char(10)),replace('สวัสดีคุณ Watcharapon Charoenwongjongdee\n\nมีข้อความใหม่ใน Ticket: ทดสอบ\n\nมาแล้วครับ\n\nเปิด Ticket ในระบบ: https://portal.doaction.co.th/tickets/AQf4RKH6TyrEktiVlBMQG\n\n— DoAction','\n',char(10)),'ticket_reply_to_client','sent',NULL,1775043280);
INSERT INTO "email_logs" ("id","to_email","to_name","subject","html_body","text_body","source","status","error_message","created_at") VALUES('K02QzxmL625oHNP31FBXr','mraumkub@gmail.com','Watcharapon Charoenwongjongdee','ลิ้งก์เข้าสู่ระบบ do action portal',replace('<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>เข้าสู่ระบบ do action portal</title>\n</head>\n<body style="margin:0;padding:0;background:#f8fafc;font-family:''Inter'',ui-sans-serif,system-ui,sans-serif;">\n  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8fafc;padding:40px 16px;">\n    <tr>\n      <td align="center">\n        <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.08);">\n\n          <!-- Header gradient bar -->\n          <tr>\n            <td style="background:linear-gradient(135deg,#1e293b 0%,#4c1d95 100%);height:6px;"></td>\n          </tr>\n\n          <!-- Logo row -->\n          <tr>\n            <td style="padding:32px 40px 0;">\n              <table cellpadding="0" cellspacing="0">\n                <tr>\n                  <td style="background:#f0d800;border-radius:8px;width:32px;height:32px;text-align:center;vertical-align:middle;">\n                    <span style="font-weight:700;font-size:14px;color:#0f172a;">D</span>\n                  </td>\n                  <td style="padding-left:10px;vertical-align:middle;">\n                    <span style="font-size:20px;font-weight:700;color:#0f172a;letter-spacing:-0.3px;">do action</span>\n                    <span style="font-size:13px;color:#64748b;margin-left:6px;">Client Portal</span>\n                  </td>\n                </tr>\n              </table>\n            </td>\n          </tr>\n\n          <!-- Body -->\n          <tr>\n            <td style="padding:32px 40px;">\n              <p style="margin:0 0 8px;font-size:22px;font-weight:600;color:#0f172a;">\n                สวัสดีคุณ Watcharapon Charoenwongjongdee\n              </p>\n              <p style="margin:0 0 28px;font-size:14px;color:#475569;line-height:1.7;">\n                ทีม do action ได้รับคำขอเข้าสู่ระบบจากอีเมลของคุณ<br>คลิกปุ่มด้านล่างเพื่อเข้าสู่ระบบ Client Portal\n              </p>\n\n              <!-- CTA Button -->\n              <table cellpadding="0" cellspacing="0" style="margin-bottom:28px;">\n                <tr>\n                  <td style="border-radius:8px;background:#7c3aed;">\n                    <a href="https://portal.doaction.co.th/magic-link?token=F0GFR72qtvbDNBFgKCtSmluFZW12R2bXe3GlKWiNTqe0q3pr"\n                       style="display:inline-block;padding:14px 32px;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;border-radius:8px;letter-spacing:0.1px;">\n                      เข้าสู่ระบบ &rarr;\n                    </a>\n                  </td>\n                </tr>\n              </table>\n\n              <!-- Fallback URL -->\n              <p style="margin:0 0 4px;font-size:12px;color:#94a3b8;">\n                หากปุ่มด้านบนไม่ทำงาน ให้คัดลอก URL นี้ไปวางในเบราว์เซอร์:\n              </p>\n              <p style="margin:0;font-size:12px;word-break:break-all;">\n                <a href="https://portal.doaction.co.th/magic-link?token=F0GFR72qtvbDNBFgKCtSmluFZW12R2bXe3GlKWiNTqe0q3pr" style="color:#7c3aed;">https://portal.doaction.co.th/magic-link?token=F0GFR72qtvbDNBFgKCtSmluFZW12R2bXe3GlKWiNTqe0q3pr</a>\n              </p>\n            </td>\n          </tr>\n\n          <!-- Divider -->\n          <tr>\n            <td style="padding:0 40px;">\n              <hr style="border:none;border-top:1px solid #e2e8f0;margin:0;" />\n            </td>\n          </tr>\n\n          <!-- Footer -->\n          <tr>\n            <td style="padding:24px 40px 32px;">\n              <p style="margin:0 0 4px;font-size:12px;color:#94a3b8;">\n                ⏱ ลิ้งก์นี้จะหมดอายุใน <strong style="color:#64748b;">15 นาที</strong>\n              </p>\n              <p style="margin:0;font-size:12px;color:#94a3b8;">\n                หากคุณไม่ได้ขอลิ้งก์นี้ กรุณาเพิกเฉยต่ออีเมลฉบับนี้\n              </p>\n              <p style="margin:16px 0 0;font-size:12px;color:#cbd5e1;">\n                do action Co., Ltd. &nbsp;|&nbsp; aum@doaction.co.th\n              </p>\n            </td>\n          </tr>\n\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>','\n',char(10)),replace('สวัสดีคุณ Watcharapon Charoenwongjongdee\n\nคลิกลิ้งก์ด้านล่างเพื่อเข้าสู่ระบบ (หมดอายุใน 15 นาที)\n\nhttps://portal.doaction.co.th/magic-link?token=F0GFR72qtvbDNBFgKCtSmluFZW12R2bXe3GlKWiNTqe0q3pr\n\nหากคุณไม่ได้ขอลิ้งก์นี้ กรุณาเพิกเฉย\n\n— ทีม do action','\n',char(10)),'admin_send_magic_link','sent',NULL,1775134802);
