48b;">15 นาที</strong>\n              </p>\n              <p style="margin:0;font-size:12px;color:#94a3b8;">\n                หากคุณไม่ได้ขอลิ้งก์นี้ กรุณาเพิกเฉยต่ออีเมลฉบับนี้\n              </p>\n              <p style="margin:16px 0 0;font-size:12px;color:#cbd5e1;">\n                do action Co., Ltd. &nbsp;|&nbsp; aum@doaction.co.th\n              </p>\n            </td>\n          </tr>\n\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>','\n',char(10)),replace('สวัสดีคุณ K. Siwaroj\n\nคลิกลิ้งก์ด้านล่างเพื่อเข้าสู่ระบบ (หมดอายุใน 15 นาที)\n\nhttps://portal.doaction.co.th/magic-link?token=md5xmPvJF5O3cByPAlLLokrEDeoRJEsDZcrfQcFoKC9CFcsy\n\nหากคุณไม่ได้ขอลิ้งก์นี้ กรุณาเพิกเฉย\n\n— ทีม do action','\n',char(10)),'admin_client_invite','sent',NULL,1775184111);
INSERT INTO "email_logs" ("id","to_email","to_name","subject","html_body","text_body","source","status","error_message","created_at") VALUES('RGRXySFLpE8P6H4xXtVkS','classpublishing.thailand@gmail.com','K. Siwaroj','รายงานประจำเดือน เมษายน 2569 พร้อมแล้ว — บริษัท สำนักพิมพ์ห้องเรียน จำกัด',replace('<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>รายงานประจำเดือน เมษายน 2569 พร้อมแล้ว — บริษัท สำนักพิมพ์ห้องเรียน จำกัด</title>\n</head>\n<body style="margin:0;padding:0;background-color:#f1f5f9;font-family:system-ui,-apple-system,''Segoe UI'',Roboto,sans-serif;">\n  <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background-color:#f1f5f9;padding:32px 16px;">\n    <tr>\n      <td align="center">\n        <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="max-width:560px;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(15,23,42,0.08);">\n          <tr>\n            <td style="height:4px;background:linear-gradient(90deg,#F0D800,#EAB308);"></td>\n          </tr>\n          <tr>\n            <td style="padding:28px 28px 8px;">\n              <p style="margin:0;font-size:12px;font-weight:600;letter-spacing:0.06em;text-transform:uppercase;color:#64748b;">do action · Client Portal</p>\n              <h1 style="margin:12px 0 0;font-size:22px;line-height:1.3;color:#0f172a;">รายงานประจำเดือนพร้อมแล้ว</h1>\n              <p style="margin:12px 0 0;font-size:15px;line-height:1.6;color:#475569;">\n                สวัสดีคุณ <strong style="color:#0f172a;">K. Siwaroj</strong><br /><strong style="color:#0f172a;">บริษัท สำนักพิมพ์ห้องเรียน จำกัด</strong>\n              </p>\n              <p style="margin:16px 0 0;font-size:15px;line-height:1.6;color:#475569;">\n                รายงาน <strong style="color:#0f172a;">รายงานประจำเดือน เมษายน 2569</strong> สำหรับ <strong style="color:#0f172a;">เมษายน 2569</strong> ได้เผยแพร่ใน Portal แล้ว\n              </p>\n              \n            </td>\n          </tr>\n          <tr>\n            <td style="padding:8px 28px 28px;">\n              <table role="presentation" cellspacing="0" cellpadding="0" style="margin-top:8px;">\n                <tr>\n                  <td style="border-radius:10px;background:#0f172a;">\n                    <a href="https://portal.doaction.co.th/public/report/G8JxurxwYMaUpdCKUwnRv?t=eyJyZXBvcnRJZCI6Ikc4Snh1cnh3WU1hVXBkQ0tVd25SdiIsImVtYWlsIjoiY2xhc3NwdWJsaXNoaW5nLnRoYWlsYW5kQGdtYWlsLmNvbSIsImV4cCI6MTc3NjM5NjUxNX0.ptsshcOSmJC7qOTjfCFe8s8U0ble-_lWpmZt8aRF9Zk" target="_blank" rel="noopener noreferrer"\n                      style="display:inline-block;padding:14px 28px;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;">\n                      เปิดรายงานใน Portal\n                    </a>\n                  </td>\n                </tr>\n              </table>\n              <p style="margin:20px 0 0;font-size:13px;line-height:1.5;color:#94a3b8;">\n                หากปุ่มไม่ทำงาน คัดลอกลิงก์นี้ไปวางในเบราว์เซอร์:<br />\n                <span style="word-break:break-all;color:#64748b;">https://portal.doaction.co.th/public/report/G8JxurxwYMaUpdCKUwnRv?t=eyJyZXBvcnRJZCI6Ikc4Snh1cnh3WU1hVXBkQ0tVd25SdiIsImVtYWlsIjoiY2xhc3NwdWJsaXNoaW5nLnRoYWlsYW5kQGdtYWlsLmNvbSIsImV4cCI6MTc3NjM5NjUxNX0.ptsshcOSmJC7qOTjfCFe8s8U0ble-_lWpmZt8aRF9Zk</span>\n              </p>\n            </td>\n          </tr>\n          <tr>\n            <td style="padding:16px 28px 24px;border-top:1px solid #e2e8f0;background:#fafafa;">\n              <p style="margin:0;font-size:12px;color:#94a3b8;line-height:1.5;">\n                อีเมลนี้ส่งจาก do action portal แจ้งเตือนรายงานประจำเดือน<br />หากมีคำถาม ติดต่อทีม do action ได้ตามช่องทางที่คุณคุ้นเคย\n              </p>\n            </td>\n          </tr>\n        </table>\n      </td>\n    </tr>\n  </table>\n</body>\n</html>','\n',char(10)),replace('สวัสดีคุณ K. Siwaroj (บริษัท สำนักพิมพ์ห้องเรียน จำกัด)\nรายงาน "รายงานประจำเดือน เมษายน 2569" สำหรับ เมษายน 2569 พร้อมแล้วใน do action portal\nเปิดรายงานใน Portal: https://portal.doaction.co.th/public/report/G8JxurxwYMaUpdCKUwnRv?t=eyJyZXBvcnRJZCI6Ikc4Snh1cnh3WU1hVXBkQ0tVd25SdiIsImVtYWlsIjoiY2xhc3NwdWJsaXNoaW5nLnRoYWlsYW5kQGdtYWlsLmNvbSIsImV4cCI6MTc3NjM5NjUxNX0.ptsshcOSmJC7qOTjfCFe8s8U0ble-_lWpmZt8aRF9Zk\n— do action','\n',char(10)),'report_notify','sent',NULL,1775186917);
CREATE TABLE contract_warning_logs (
  id TEXT PRIMARY KEY,
  client_id TEXT NOT NULL REFERENCES clients(id) ON DELETE CASCADE,
  warning_stage TEXT NOT NULL CHECK(warning_stage IN ('first', 'second', 'third')),
  contract_end TEXT NOT NULL,
  sent_at INTEGER NOT NULL DEFAULT (unixepoch()),
  UNIQUE(client_id, warning_stage, contract_end)
);
CREATE INDEX idx_notifications_user_id ON notifications(user_id, read);
CREATE INDEX idx_ticket_messages_ticket_id ON ticket_messages(ticket_id);
CREATE INDEX idx_tickets_client_id ON support_tickets(client_id);
CREATE INDEX idx_reports_client_id ON monthly_reports(client_id);
CREATE INDEX idx_clients_user_id ON clients(user_id);
CREATE INDEX idx_ticket_attachments_ticket_id
  ON ticket_attachments(ticket_id, created_at);
CREATE INDEX idx_email_logs_created_at ON email_logs(created_at DESC);
CREATE INDEX idx_email_logs_to_email ON email_logs(to_email);
CREATE INDEX idx_contract_warning_logs_client ON contract_warning_logs(client_id);
CREATE INDEX idx_clients_deleted_at ON clients(deleted_at);
